    rtt = max(memory.rtt_ratio, 0.5)

    recv_rate = 1.0 / rec
    send_rate = 1.0 / send
    util = send / rec
    bw_trend = slow_rec / rec

    st["rtt_filt"] = 0.85 * st["rtt_filt"] + 0.15 * rtt
    drtt = st["rtt_filt"] - st["last_rtt"]
    st["last_rtt"] = st["rtt_filt"]
    st["trend"] = 0.8 * st["trend"] + 0.2 * drtt

    if st["phase"] == "startup":
        if rtt > 1.30 or util > 1.20:
            st["phase"] = "drain"
            st["hold"] = 4

    if st["phase"] == "drain":
        st["hold"] -= 1
        if st["hold"] <= 0:
            st["phase"] = "steady"

    if rtt > 2.6:
        mult = 0.45
        inc = 0
    elif rtt > 2.0:
        mult = 0.62
        inc = 0
    elif rtt > 1.6:
        mult = 0.82
        inc = -1
    else:
        mult = 1.0
        if st["phase"] == "startup":
            if rtt < 1.10 and util < 1.05:
                inc = 4
            elif rtt < 1.20:
                inc = 3
            else:
                inc = 2
        elif st["phase"] == "drain":
            inc = -1
        else:
            q = st["rtt_filt"] - 1.0
            if rtt < 1.3:
                base = 1.0 + max(0.0, (1.20 - rtt)) * 4.0
                if util < 0.95:
                    base += 1.2
                elif util < 1.02:
                    base += 0.5
                if st["trend"] > 0.01:
                    base -= 0.8
                if bw_trend < 0.97:
                    base -= 0.4
                inc = max(1, int(round(base)))
            else:
                dec = 1 + int(min(3.0, (rtt - 1.3) * 4.0 + max(0.0, st["trend"] * 50.0)))
                inc = -dec

    gain = 1.0
    if rtt < 1.10:
        gain = 1.20
    elif rtt < 1.30:
        gain = 1.08
    elif rtt > 1.8:
        gain = 0.88
    elif rtt > 1.4:
        gain = 0.95

    if util > 1.15:
        gain *= 0.92
    elif util < 0.9 and rtt < 1.35:
        gain *= 1.08

    target_rate = max(1e-4, recv_rate * gain)
    intersend = 1.0 / target_rate

    if rtt > 2.0:
        intersend *= 1.15
    elif rtt < 1.2 and util < 1.0:
        intersend *= 0.92

    intersend = min(200.0, max(0.0, intersend))

    if rtt < 1.3 and inc <= 0:
        inc = 1
        if mult < 1.0 and rtt < 1.2:
            mult = 1.0

    return RemyAction(window_increment=int(inc), window_multiple=float(mult), intersend=float(intersend))

