        st["cooldown"] = max(st["cooldown"], 2)
        target_rate = recv_rate * 0.82
        intersend = max(0.0, 1.0 / max(target_rate, 1e-6))
        return RemyAction(window_increment=0, window_multiple=0.7, intersend=intersend)

    if rtt < 1.3:
        if st["cooldown"] > 0:
            inc = 1
        else:
            headroom = max(0.0, 1.12 - util)
            inc = 1 + int(min(3, math.floor(headroom * 10.0)))
            if st["trend"] < -0.01 and util < 1.05:
                inc += 1
        gain = 1.06 + max(0.0, min(0.10, (1.2 - rtt) * 0.25))
        target_rate = recv_rate * gain
        intersend = max(0.0, 1.0 / max(target_rate, 1e-6))
        return RemyAction(window_increment=max(1, inc), window_multiple=1.0, intersend=intersend)

    mild = min(1.0, max(0.0, (rtt - 1.3) / 0.7))
