        st["base_rec"] = rec
    else:
        # Track best (fastest) receive spacing slowly
        st["base_rec"] = min(st["base_rec"] * 1.0005, rec, st["base_rec"])

    # Congestion score (continuous)
    q = max(0.0, rtt - 1.0)
