    dr = rtt - st["last_rtt"]
    st["trend"] = 0.82 * st["trend"] + 0.18 * dr
    st["last_rtt"] = rtt

    if rec < st["base_rec"]:
        st["base_rec"] = 0.9 * st["base_rec"] + 0.1 * rec
    else:
        st["base_rec"] = min(slow_rec, st["base_rec"] * 1.001 + 0.001 * rec)
    base_rec = max(st["base_rec"], 1e-6)

    q_err = st["q_ewma"] - 1.0
    gain = 1.06 - 0.38 * q_err - 0.55 * st["trend"]

    if st["util_ewma"] > 1.04 and rtt < 1.35:
        gain *= 1.06
    elif st["util_ewma"] < 0.95:
        gain *= 0.92

    if rtt > 2.0:
        gain = min(gain, 0.62)
    elif rtt > 1.6:
        gain = min(gain, 0.82)

    gain = max(0.45, min(1.25, gain))
    target_intersend = max(0.0, min(2000.0, base_rec / gain))

    if st["hold"] > 0:
        st["hold"] -= 1

    if st["phase"] == "startup":
        if rtt < 1.15 and st["util_ewma"] >= 0.98:
            return RemyAction(window_increment=4, window_multiple=1.0, intersend=target_intersend * 0.9)
        if rtt < 1.3:
            return RemyAction(window_increment=2, window_multiple=1.0, intersend=target_intersend * 0.95)
        st["phase"] = "steady"
        st["hold"] = 2
        if rtt > 2.0:
            return RemyAction(window_increment=0, window_multiple=0.6, intersend=target_intersend)
        return RemyAction(window_increment=1, window_multiple=0.92, intersend=target_intersend)

    if rtt > 2.4:
        st["hold"] = 3
        st["eq_count"] = 0
        return RemyAction(window_increment=0, window_multiple=0.45, intersend=target_intersend)
    if rtt > 2.0:
        st["hold"] = 2
        st["eq_count"] = 0
        return RemyAction(window_increment=0, window_multiple=0.58, intersend=target_intersend)

    if 1.2 <= rtt <= 1.5 and abs(st["trend"]) < 0.01:
        st["eq_count"] = min(20, st["eq_count"] + 1)
    else:
        st["eq_count"] = max(0, st["eq_count"] - 1)

    if st["hold"] > 0:
