            inc = 3 if st["util_ewma"] > 1.0 else 2
        else:
            inc = 2 if st["util_ewma"] >= 0.98 else 1
        if st["eq_count"] > 10:
            inc = max(1, inc - 1)
        return RemyAction(window_increment=inc, window_multiple=1.0, intersend=target_intersend)

    if rtt < 1.7:
        dec = int(min(3, max(0, (rtt - 1.3) * 7 + max(0.0, st["trend"] * 20))))
        mult = 1.0 - min(0.08, 0.01 + 0.03 * max(0.0, rtt - 1.3))
        return RemyAction(window_increment=-dec, window_multiple=mult, intersend=target_intersend)

    dec = int(min(4, 1 + (rtt - 1.7) * 5))
    mult = max(0.75, 0.9 - 0.08 * (rtt - 1.7))
    return RemyAction(window_increment=-dec, window_multiple=mult, intersend=target_intersend)

