    rec = max(memory.rec_ewma, 1e-6)
    slow_rec = max(memory.slow_rec_ewma, 1e-6)
    rtt = max(memory.rtt_ratio, 1.0)

    util = send / rec
    st["util_ewma"] = 0.88 * st["util_ewma"] + 0.12 * util
    st["rtt_ewma"] = 0.9 * st["rtt_ewma"] + 0.1 * rtt

    dr = rtt - st["last_rtt"]
    st["trend"] = 0.82 * st["trend"] + 0.18 * dr
    st["last_rtt"] = rtt

    if rec <= st["base_rec"] * 1.03:
        st["base_rec"] = 0.97 * st["base_rec"] + 0.03 * rec
    else:
        st["base_rec"] = min(st["base_rec"] * 1.0003, slow_rec)
    base_rec = max(st["base_rec"], 1e-6)

    # pacing gain (rate-based): intersend ~= base_rec / gain
    q = st["rtt_ewma"]
    gain = 1.0 + 0.55 * (1.15 - q) - 0.9 * max(0.0, q - 1.15)
    gain -= 1.2 * max(0.0, st["trend"])
    gain += 0.25 * max(0.0, 1.0 - st["util_ewma"])
    gain = min(1.35, max(0.45, gain))
    intersend = max(0.0, min(2000.0, base_rec / max(gain, 1e-6)))

    # hard congestion protection
    if rtt > 2.5:
        st["phase"] = "steady"
        st["hold"] = 3
        return RemyAction(window_increment=0, window_multiple=0.42, intersend=intersend)
    if rtt > 2.0:
        st["phase"] = "steady"
        st["hold"] = 2
        return RemyAction(window_increment=0, window_multiple=0.58, intersend=intersend)

    if st["phase"] == "startup":
        if rtt < 1.12:
            inc = 4
        elif rtt < 1.22:
            inc = 3
        elif rtt < 1.3:
            inc = 2
        else:
            st["phase"] = "steady"
            st["hold"] = 1
            inc = 1  # must increase when rtt < 1.3; here rtt>=1.3 transition edge
        if rtt >= 1.35 or st["trend"] > 0.03:
            st["phase"] = "steady"
        return RemyAction(window_increment=inc, window_multiple=1.0, intersend=intersend)

    if st["hold"] > 0:
        st["hold"] -= 1
        if rtt < 1.3:
            return RemyAction(window_increment=1, window_multiple=1.0, intersend=intersend)
        return RemyAction(window_increment=0, window_multiple=0.985, intersend=intersend)

    # proportional steady-state cwnd control
    if rtt < 1.3:
        headroom = 1.3 - rtt
        inc = 1 + int(min(3, headroom * 8.0))
        if st["util_ewma"] > 1.03 and rtt < 1.2:
            inc += 1
        inc = min(5, max(1, inc))
        return RemyAction(window_increment=inc, window_multiple=1.0, intersend=intersend)

    if rtt < 1.8:
        x = (rtt - 1.3) / 0.5
        mult = 1.0 - 0.08 * x - 0.05 * max(0.0, st["trend"])
        mult = min(0.995, max(0.88, mult))
        dec = int(max(0, min(2, math.floor((rtt - 1.3) * 4.0))))
        return RemyAction(window_increment=-dec, window_multiple=mult, intersend=intersend)

    mult = max(0.7, 0.9 - 0.25 * (rtt - 1.8))
    return RemyAction(window_increment=-1, window_multiple=mult, intersend=intersend)

